parameters.query:
SELECT direction, channel, text, created_at
FROM outreach_messages WHERE lead_id = $1::int
ORDER BY created_at;

parameters.jsCode:
// Собираем контекст для AI: сам лид + история переписки.
const lead = $('Load Lead').item.json;
const history = $input.all().map(i => i.json);
const formattedHistory = history.length
  ? history.map(h => `[${h.created_at}] ${h.direction === 'in' ? 'CLIENT' : 'US'}: ${h.text}`).join('\n')
  : '(переписки ещё нет — нужно начать)';
return [{
  json: {
    lead_id: lead.id,
    title: lead.title,
    niche: lead.niche,
    metadata: lead.metadata,
    status: lead.status,
    history: formattedHistory,
  }
}];

