// Парсим JSON-ответ AI и валидируем.
let decision;
try {
  decision = JSON.parse($json.output);
} catch (e) {
  throw new Error('Sales Agent did not return valid JSON: ' + $json.output.slice(0, 200));
}
const stages = ['first_contact','qualifying','meeting_set','won','lost'];
if (!stages.includes(decision.stage)) throw new Error('invalid stage: ' + decision.stage);
const lead = $('Build Context').item.json;
return [{ json: { ...decision, lead_id: lead.lead_id } }];
